      "  boolean absoluteValueIsPositive(@ForAll int number) {",
      "    return Math.abs(number) >= 0;",
      "  }",
      "  @Provide",
      "  Arbitrary<String> names() {",
      "    return Arbitraries.strings().alpha().ofMinLength(1).ofMaxLength(12).filter(value -> !value.isBlank());",
      "  }",
