      "rg \"log_artifact|wandb.Artifact|wandb.Table|upload\\(|track_files|dataset|media|Image\" .",
      "rg \"wandb sync|neptune sync|offline|upload-artifact|tracking-report|metrics.json\" .github workflows ."
