      "  'push' if 'writer';",
      "  'writer' if 'admin';",
      "}",
      "allow(actor, action, resource) if has_permission(actor, action, resource);",
      "has_permission(actor, 'push', repo: Repository) if has_role(actor, 'writer', repo);",
      "allow_field(actor, 'read', resource, field) if field = 'title';",
